#!/bin/bash
C='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
c2n(){ [[ "$1" == '=' ]]&&echo -1;[[ "$1" == 'A' ]]&&echo 0;[[ "$1" == 'B' ]]&&echo 1;[[ "$1" == 'C' ]]&&echo 2;[[ "$1" == 'D' ]]&&echo 3;[[ "$1" == 'E' ]]&&echo 4;[[ "$1" == 'F' ]]&&echo 5;[[ "$1" == 'G' ]]&&echo 6;[[ "$1" == 'H' ]]&&echo 7;[[ "$1" == 'I' ]]&&echo 8;[[ "$1" == 'J' ]]&&echo 9;[[ "$1" == 'K' ]]&&echo 10;[[ "$1" == 'L' ]]&&echo 11;[[ "$1" == 'M' ]]&&echo 12;[[ "$1" == 'N' ]]&&echo 13;[[ "$1" == 'O' ]]&&echo 14;[[ "$1" == 'P' ]]&&echo 15;[[ "$1" == 'Q' ]]&&echo 16;[[ "$1" == 'R' ]]&&echo 17;[[ "$1" == 'S' ]]&&echo 18;[[ "$1" == 'T' ]]&&echo 19;[[ "$1" == 'U' ]]&&echo 20;[[ "$1" == 'V' ]]&&echo 21;[[ "$1" == 'W' ]]&&echo 22;[[ "$1" == 'X' ]]&&echo 23;[[ "$1" == 'Y' ]]&&echo 24;[[ "$1" == 'Z' ]]&&echo 25;[[ "$1" == 'a' ]]&&echo 26;[[ "$1" == 'b' ]]&&echo 27;[[ "$1" == 'c' ]]&&echo 28;[[ "$1" == 'd' ]]&&echo 29;[[ "$1" == 'e' ]]&&echo 30;[[ "$1" == 'f' ]]&&echo 31;[[ "$1" == 'g' ]]&&echo 32;[[ "$1" == 'h' ]]&&echo 33;[[ "$1" == 'i' ]]&&echo 34;[[ "$1" == 'j' ]]&&echo 35;[[ "$1" == 'k' ]]&&echo 36;[[ "$1" == 'l' ]]&&echo 37;[[ "$1" == 'm' ]]&&echo 38;[[ "$1" == 'n' ]]&&echo 39;[[ "$1" == 'o' ]]&&echo 40;[[ "$1" == 'p' ]]&&echo 41;[[ "$1" == 'q' ]]&&echo 42;[[ "$1" == 'r' ]]&&echo 43;[[ "$1" == 's' ]]&&echo 44;[[ "$1" == 't' ]]&&echo 45;[[ "$1" == 'u' ]]&&echo 46;[[ "$1" == 'v' ]]&&echo 47;[[ "$1" == 'w' ]]&&echo 48;[[ "$1" == 'x' ]]&&echo 49;[[ "$1" == 'y' ]]&&echo 50;[[ "$1" == 'z' ]]&&echo 51;[[ "$1" == '0' ]]&&echo 52;[[ "$1" == '1' ]]&&echo 53;[[ "$1" == '2' ]]&&echo 54;[[ "$1" == '3' ]]&&echo 55;[[ "$1" == '4' ]]&&echo 56;[[ "$1" == '5' ]]&&echo 57;[[ "$1" == '6' ]]&&echo 58;[[ "$1" == '7' ]]&&echo 59;[[ "$1" == '8' ]]&&echo 60;[[ "$1" == '9' ]]&&echo 61;[[ "$1" == '+' ]]&&echo 62;[[ "$1" == '/' ]]&&echo 63;}
enc(){ while IFS= read -r -n3 b;do local n=0 l=${#b};[[ $l -eq 0 ]]&&break;for i in 0 1 2;do local v=0;[[ $i -lt $l ]]&&v=$(printf '%d' "'${b:$i:1}");n=$((n<<8|v));done;local p=$((3-l));for i in 0 1 2 3;do local pos=$((3-i));local idx=$(((n>>(pos*6))&63));[[ $i -ge $((4-p)) ]]&&echo -n '=' || echo -n "${C:idx:1}";done;done;}
dec(){ while IFS= read -r -n4 b;do local n=0 p=0;[[ ${#b} -eq 0 ]]&&break;for i in 0 1 2 3;do local v=$(c2n "${b:$i:1}");[[ $v -lt 0 ]]&&{ v=0;p=$((p+1)); };n=$((n*64+v));done;for i in 2 1 0;do [[ $i -lt $p ]]&&break;printf "\\$(printf '%03o' $(((n>>(i*8))&255)))";done;done;}
[[ "$1" == "-d" ]]&&dec||enc
